  }

  // 4. Validate status — double-refund guard
  if (transaction.status === 'refunded') {
    return NextResponse.json({ error: 'העסקה כבר הוחזרה' }, { status: 400 })
  }

  if (transaction.status !== 'succeeded') {
    return NextResponse.json(
      { error: 'Only succeeded transactions can be refunded' },
      { status: 400 },
    )
  }

  // 5. Call provider refund
  const { provider, providerTransactionId, amount } = transaction as {
    provider: 'stripe' | 'paypal'
    providerTransactionId: string
    amount: number
  }

  try {
    if (provider === 'stripe') {
      await refundStripe(providerTransactionId, amount)
    } else if (provider === 'paypal') {
      await refundPayPal(providerTransactionId, amount)
    } else {
      return NextResponse.json({ error: 'Unknown payment provider' }, { status: 400 })
    }
  } catch (err) {
    payload.logger.error({ error: err, transactionId: id, provider }, 'Refund operation failed')
    return NextResponse.json({ error: 'Refund operation failed' }, { status: 500 })
  }

  // 6. Update status to refunded
  await payload.update({
    collection: 'transactions',
    id,
    data: { status: 'refunded' },
    overrideAccess: true,
  })

  return NextResponse.json({ success: true })
}

/**
 * Integration test: lesson duplication orchestrator.
 *
 * Acceptance criteria:
 *  1. Orchestrator runs at most 4 strategy calls in parallel
 *  2. One exercise failing does not abort the run — remaining exercises complete
 *  3. Failures appear in the DB record as the run progresses (live streaming, asserted by polling)
 *  4. Final status is succeeded only when failures array is empty, else needs_review
 *  5. 5-exercise lesson with one forced failure → needs_review with 4 succeeded + 1 failure entry
 */
import { afterAll, beforeAll, beforeEach, describe, expect, it, vi } from 'vitest'
import { getPayload, type Payload } from 'payload'
import config from '@payload-config'

import { getDefaultTenantSlug } from '@/server/repos/tenant/get-default-tenant'
import { runDuplicationOrchestrator } from '@/server/services/lesson-duplication/orchestrator'

// Mock the variation service so AiVariationStrategy (used for medium/deep level)
// does not make real LLM calls in the integration test environment.
// Uses hoisted state for reliable module-level tracking across test runs.
const { mockState } = vi.hoisted(() => {
  let callCount = 0
  return {
    mockState: {
      reset() {
        callCount = 0
      },
      get next() {
        callCount++
        return callCount
      },
    },
  }
})

